    /**
     * @method
     * @name grvt#watchOrderBookForSymbols
     * @description watches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @see https://api-docs.grvt.io/market_data_streams/#orderbook-snap
     * @see https://api-docs.grvt.io/market_data_streams/#orderbook-delta
     * @param {string[]} symbols unified array of symbols
     * @param {int} [limit] the maximum amount of order book entries to return.
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrderBookForSymbols(Object symbols2, Object... optionalArgs)
    {
        final Object symbols3 = symbols2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object symbols = symbols3;
            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object channel = null;
            var channelparametersVariable = this.handleOptionAndParams(parameters, "watchOrderBook", "channel", "v1.book.d");
            channel = ((java.util.List<Object>) channelparametersVariable).get(0);
            parameters = ((java.util.List<Object>) channelparametersVariable).get(1);
            Object isSnapshot = Helpers.isEqual(channel, "v1.book.s");
            Object symbolsLength = Helpers.getArrayLength(symbols);
            if (Helpers.isTrue(Helpers.isEqual(symbolsLength, 0)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " watchOrderBookForSymbols() requires a non-empty array of symbols")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(limit, null)))
            {
                var limitparametersVariable = this.handleOptionAndParams(parameters, "watchOrderBook", "limit", 100);
                limit = ((java.util.List<Object>) limitparametersVariable).get(0);
                parameters = ((java.util.List<Object>) limitparametersVariable).get(1);
            }
            Object interval = null;
            var intervalparametersVariable = this.handleOptionAndParams(parameters, "watchOrderBook", "interval", 500);
            interval = ((java.util.List<Object>) intervalparametersVariable).get(0);
            parameters = ((java.util.List<Object>) intervalparametersVariable).get(1);
            symbols = this.marketSymbols(symbols);
            Object extraPart = ((Helpers.isTrue(isSnapshot))) ? (Helpers.add(Helpers.add(String.valueOf(((String)interval)), "-"), String.valueOf(limit))) : String.valueOf(((String)interval));
            Object rawHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
            {
                Object symbol = Helpers.GetValue(symbols, i);
                Object market = this.market(symbol);
                Object marketId = Helpers.GetValue(market, "id");
                ((java.util.List<Object>)rawHashes).add(Helpers.add(Helpers.add(marketId, "@"), extraPart));
                ((java.util.List<Object>)messageHashes).add(Helpers.add("orderbook::", Helpers.GetValue(market, "symbol")));
            }
            final Object finalChannel = channel;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "stream", finalChannel );
                put( "selectors", rawHashes );
            }};
            Object orderbook = (this.subscribeMultiple(messageHashes, this.extend(request, parameters), rawHashes)).join();
            return Helpers.callDynamically(orderbook, "limit", new Object[]{});
        });

    }

    public void handleOrderBook(Client client, Object message)
    {
        //
        //    {
        //        "stream": "v1.book.s",
        //        "selector": "BTC_USDT_Perp@500-100",
        //        "sequence_number": "0",
        //        "feed": {
        //            "event_time": "1767292408400000000",
        //            "instrument": "BTC_USDT_Perp",
        //            "bids": [
        //                {
        //                    "price": "88107.3",
        //                    "size": "5.322",
        //                    "num_orders": 11
        //                },
        //            ],
        //            "asks": [
        //                {
        //                    "price": "88107.4",
        //                    "size": "5.273",
        //                    "num_orders": 37
        //                },
        //            ]
        //        },
        //        "prev_sequence_number": "0"
        //    }
        //
        Object data = this.safeDict(message, "feed", new java.util.HashMap<String, Object>() {{}});
        Object selector = this.safeString(message, "selector", "");
        Object parts = Helpers.split(selector, "@");
        Object marketId = this.safeString(parts, 0);
        Object market = this.safeMarket(marketId, null);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeIntegerProduct(data, "event_time", 0.000001);
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook());
        }
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        Object sequenceNumber = this.safeInteger(message, "sequence_number", 0);
        Object stream = this.safeString(message, "stream");
        Object isSnapshotChannel = Helpers.isEqual(stream, "v1.book.s");
        Object isSnapshotMessage = Helpers.isLessThanOrEqual(sequenceNumber, 0);
        if (Helpers.isTrue(Helpers.isTrue(isSnapshotChannel) || Helpers.isTrue(isSnapshotMessage)))
        {
            Object snapshot = this.parseOrderBook(data, symbol, timestamp, "bids", "asks", "price", "size");
            Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
        } else
        {
            Object asks = this.safeList(data, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object bids = this.safeList(data, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            this.handleDeltasWithKeys(Helpers.GetValue(orderbook, "asks"), asks, "price", "size");
            this.handleDeltasWithKeys(Helpers.GetValue(orderbook, "bids"), bids, "price", "size");
            Helpers.addElementToObject(orderbook, "timestamp", timestamp);
            Helpers.addElementToObject(orderbook, "datetime", this.iso8601(timestamp));
        }
        // grvt defaults to the delta channel (v1.book.d); if the very first
        // message is a delta, the freshly-created orderbook has symbol=null
        // because no snapshot has reset it yet. Set it unconditionally — we
        // know the symbol from the selector regardless of channel. Java's
        // typed WsOrderBook surfaces this as `"symbol":null` in the output;
        // Python/JS dict-backed orderbooks happen to mask it but the
        // unconditional assignment is correct for every language.
        Helpers.addElementToObject(orderbook, "symbol", symbol);
        Helpers.addElementToObject(orderbook, "nonce", sequenceNumber);
        Object messageHash = Helpers.add("orderbook::", symbol);
        Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
        client.resolve(orderbook, messageHash);
    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.checkRequiredCredentials();
            (this.signIn()).join();
            Object wsOptions = this.safeDict(this.options, "ws", new java.util.HashMap<String, Object>() {{}});
            Object authenticated = this.safeString(wsOptions, "token");
            if (Helpers.isTrue(Helpers.isEqual(authenticated, null)))
            {
                Object accountId = this.safeString(this.options, "AuthAccountId");
                Object cookieValue = this.safeString(this.options, "AuthCookieValue");
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(cookieValue, null)) || Helpers.isTrue(Helpers.isEqual(accountId, null))))
                {
                    throw new AuthenticationError((String)Helpers.add(this.id, " : at first, you need to authenticate with exchange using signIn() method.")) ;
                }
                final Object finalCookieValue = cookieValue;
                final Object finalAccountId = accountId;
                Object defaultOptions = new java.util.HashMap<String, Object>() {{
                    put( "ws", new java.util.HashMap<String, Object>() {{
                        put( "options", new java.util.HashMap<String, Object>() {{
                            put( "headers", new java.util.HashMap<String, Object>() {{
                                put( "Cookie", finalCookieValue );
                                put( "X-Grvt-Account-Id", finalAccountId );
                            }} );
                        }} );
                    }} );
                }};
                this.extendExchangeOptions(defaultOptions);
                this.client(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "privateTrading"));
            }
            return null;
        });

    }

